   260→    @Override
   261→    public void put(final Bytes key,
   262→                    final byte[] value) {
   263→        Objects.requireNonNull(key, "key cannot be null");
   264→        validateStoreOpen();
   265→        lock.writeLock().lock();
   266→        try {
   267→            validateStoreOpen();
   268→            // for null bytes, we still put it into cache indicating tombstones
   269→            putInternal(key, value);
   270→        } finally {
   271→            lock.writeLock().unlock();
   272→        }
   273→    }
   274→
   275→    private void putInternal(final Bytes key,
   276→                             final byte[] value) {
   277→        synchronized (position) {
   278→            internalContext.cache().put(
   279→                cacheName,
   280→                key,
   281→                new LRUCacheEntry(
   282→                    value,
   283→                    internalContext.recordContext().headers(),
   284→                    true,
   285→                    internalContext.recordContext().offset(),
   286→                    internalContext.recordContext().timestamp(),
   287→                    internalContext.recordContext().partition(),
   288→                    internalContext.recordContext().topic(),
   289→                    internalContext.recordContext().sourceRawKey(),
   290→                    internalContext.recordContext().sourceRawValue()
   291→                )
   292→            );
   293→
   294→            StoreQueryUtils.updatePosition(position, internalContext);
   295→        }
   296→    }
