   298→    @Override
   299→    public byte[] putIfAbsent(final Bytes key,
   300→                              final byte[] value) {
   301→        Objects.requireNonNull(key, "key cannot be null");
   302→        validateStoreOpen();
   303→        lock.writeLock().lock();
   304→        try {
   305→            validateStoreOpen();
   306→            final byte[] v = getInternal(key);
   307→            if (v == null) {
   308→                putInternal(key, value);
   309→            }
   310→            return v;
   311→        } finally {
   312→            lock.writeLock().unlock();
   313→        }
   314→    }
   315→
   316→    @Override
   317→    public void putAll(final List<KeyValue<Bytes, byte[]>> entries) {
   318→        validateStoreOpen();
   319→        lock.writeLock().lock();
   320→        try {
   321→            validateStoreOpen();
   322→            for (final KeyValue<Bytes, byte[]> entry : entries) {
   323→                Objects.requireNonNull(entry.key, "key cannot be null");
   324→                put(entry.key, entry.value);
   325→            }
   326→        } finally {
   327→            lock.writeLock().unlock();
   328→        }
   329→    }
   330→
   331→    @Override
   332→    public byte[] delete(final Bytes key) {
   333→        Objects.requireNonNull(key, "key cannot be null");
   334→        validateStoreOpen();
   335→        lock.writeLock().lock();
   336→        try {
   337→            validateStoreOpen();
   338→            return deleteInternal(key);
   339→        } finally {
   340→            lock.writeLock().unlock();
   341→        }
   342→    }
   343→
   344→    private byte[] deleteInternal(final Bytes key) {
   345→        final byte[] v = getInternal(key);
   346→        putInternal(key, null);
   347→        return v;
   348→    }
   349→
   350→    @Override
   351→    public byte[] get(final Bytes key) {
   352→        Objects.requireNonNull(key, "key cannot be null");
   353→        validateStoreOpen();
   354→        final Lock theLock;
   355→        if (Thread.currentThread().equals(streamThread)) {
   356→            theLock = lock.writeLock();
   357→        } else {
   358→            theLock = lock.readLock();
   359→        }
   360→        theLock.lock();
   361→        try {
   362→            validateStoreOpen();
   363→            return getInternal(key);
   364→        } finally {
   365→            theLock.unlock();
   366→        }
   367→    }
   368→
   369→    private byte[] getInternal(final Bytes key) {
   370→        LRUCacheEntry entry = null;
   371→        if (internalContext.cache() != null) {
   372→            entry = internalContext.cache().get(cacheName, key);
   373→        }
   374→        if (entry == null) {
   375→            final byte[] rawValue = wrapped().get(key);
   376→            if (rawValue == null) {
   377→                return null;
   378→            }
   379→            // only update the cache if this call is on the streamThread
   380→            // as we don't want other threads to trigger an eviction/flush
   381→            if (Thread.currentThread().equals(streamThread)) {
   382→                internalContext.cache().put(cacheName, key, new LRUCacheEntry(rawValue));
   383→            }
   384→            return rawValue;
   385→        } else {
   386→            return entry.value();
   387→        }
   388→    }
