   487→    @Override
   488→    public void clearCache() {
   489→        validateStoreOpen();
   490→        lock.writeLock().lock();
   491→        try {
   492→            validateStoreOpen();
   493→            internalContext.cache().clear(cacheName);
   494→        } finally {
   495→            lock.writeLock().unlock();
   496→        }
   497→    }
   498→
   499→    @Override
   500→    public void close() {
   501→        lock.writeLock().lock();
   502→        try {
   503→            final LinkedList<RuntimeException> suppressed = executeAll(
   504→                () -> internalContext.cache().flush(cacheName),
   505→                () -> internalContext.cache().close(cacheName),
   506→                wrapped()::close
   507→            );
   508→            if (!suppressed.isEmpty()) {
   509→                throwSuppressed("Caught an exception while closing caching key value store for store " + name(),
   510→                    suppressed);
   511→            }
   512→        } finally {
   513→            lock.writeLock().unlock();
   514→        }
   515→    }
