        cache.addDirtyEntryFlushListener(namespace2, dirty -> {
            for (final ThreadCache.DirtyEntry entry : dirty) {
                cache.put(namespace1, entry.key(),
                    new LRUCacheEntry(entry.newValue(), new RecordHeaders(), true, 0L, 0L, 0, "", new byte[0], new byte[0]));
