public void resize(final long newCacheSizeBytes) {
    final boolean shrink;
    final List<NamedCache> cacheCopy;
    synchronized (this) {
        shrink = newCacheSizeBytes < maxCacheSizeBytes;
        maxCacheSizeBytes = newCacheSizeBytes;
        if (!shrink) {
            log.debug("Cache size was expanded to {}", newCacheSizeBytes);
            return;
        }
        log.debug("Cache size was shrunk to {}", newCacheSizeBytes);
        if (caches.values().isEmpty()) {
            return;
        }
        cacheCopy = new ArrayList<>(caches.values());
    }
    final CircularIterator<NamedCache> circularIterator = new CircularIterator<>(cacheCopy);
    while (sizeInBytes.get() > maxCacheSizeBytes) {
        final NamedCache cache = circularIterator.next();
        synchronized (cache) {
            final long oldSize = cache.sizeInBytes();
            cache.evict();
            sizeInBytes.getAndAdd(cache.sizeInBytes() - oldSize);
        }
        numEvicts++;
    }
}

